package inequivalent;

import org.junit.jupiter.api.Test;

import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair74Method2Test {

    private final ClonePair74 subject = new ClonePair74();

    @Test
    void method2SplitsPlainWordsOnWhitespace() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("alpha", "beta"), subject.method2("alpha\tbeta"));
    }

    @Test
    void method2KeepsSpacesInsideQuotedToken() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("alpha beta", "gamma"), subject.method2("\"alpha beta\" gamma"));
    }

    @Test
    void method2IgnoresRepeatedWhitespaceBetweenTokens() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("alpha", "beta"), subject.method2("alpha  beta"));
    }

    @Test
    void method2PreservesEscapedQuoteCharacterInsideToken() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("a\"b", "tail"), subject.method2("\"a\\\"b\" tail"));
    }

    @Test
    void method2ThrowsNullPointerExceptionForNullInput() {
        // Generated by Codex (gpt-5.4).
        assertThrows(NullPointerException.class, () -> subject.method2(null));
    }
}
